code = """import json, pandas as pd

books = pd.DataFrame(var_call_3EaRJ6UytQcCeG0aXsSYvanW)
path = var_call_JtHRrfV1YGotMWwZJ1zVT2QJ
with open(path, 'r', encoding='utf-8') as f:
    reviews_raw = json.load(f)
reviews = pd.DataFrame(reviews_raw)

# Ensure Children's Books categorization
books_cb = books[books['categories'].str.contains("Children's Books", na=False)].copy()

# Fuzzy join: ids appear as bookid_X vs purchaseid_X -> join on trailing numeric token
books_cb['id_num'] = books_cb['book_id'].str.extract(r'(\d+)$')[0].astype('Int64')
reviews['id_num'] = reviews['purchase_id'].str.extract(r'(\d+)$')[0].astype('Int64')

# Ratings numeric
reviews['rating'] = pd.to_numeric(reviews['rating'], errors='coerce')

merged = pd.merge(reviews, books_cb[['book_id','title','id_num']], on='id_num', how='inner')

grp = merged.groupby(['book_id','title'], as_index=False).agg(avg_rating=('rating','mean'), review_count=('rating','count'))
res = grp[grp['avg_rating'] >= 4.5].sort_values(['avg_rating','review_count','title'], ascending=[False, False, True])

out = res.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out))"""

